const items = $input.all();
const results = [];
for (const item of items) {
  const name = (item.json.name || '').toLowerCase();
  if (name.endsWith('.h')) {
    results.push({ json: { id: item.json.id, fileName: item.json.name } });
  }
}
if (results.length === 0) throw new Error('No .h header files found.');
return results;

const items = $input.all();
for (const item of items) {
  const fileName = item.json.pdfName || item.json.name || 'DOC.pdf';
  item.json.subject = 'API Documentation PDF Ready — XYZ Technologies';
  item.json.message = `Hello,

Your C header file API documentation PDF has been generated by XYZ Technologies.

File: ${fileName}
Uploaded to: Output folder in Google Drive
Generated: ${new Date().toUTCString()}

The PDF includes:
  - Overview
  - Functions (signatures, parameters, return values, examples)
  - Enumerators
  - Data Types & Structures
  - Constants
  - Notes

Best regards,
XYZ Technologies Automation`;
}
return items;

values.content:
You are a senior technical writer for embedded systems at XYZ Technologies. Given a C header (.h) file, extract and document everything as strict JSON — no markdown, no explanation, raw JSON only.

Return exactly this structure:
{
  "overview": "<2-3 sentence summary>",
  "functions": [
    {
      "name": "<function name>",
      "signature": "<full prototype>",
      "description": "<what it does>",
      "parameters": [
        { "name": "<param>", "type": "<type>", "description": "<desc>" }
      ],
      "returns": "<return type and meaning>",
      "example": "<minimal C usage>"
    }
  ],
  "enumerators": [
    {
      "name": "<enum type name>",
      "description": "<purpose>",
      "values": [
        { "name": "<VALUE>", "value": "<integer>", "description": "<meaning>" }
      ]
    }
  ],
  "data_types": [
    {
      "name": "<type name>",
      "kind": "<struct|union|typedef|bitfield>",
      "description": "<purpose>",
      "members": [
        { "name": "<field>", "type": "<type>", "description": "<meaning>" }
      ]
    }
  ],
  "constants": [
    { "name": "<CONSTANT_NAME>", "value": "<value>", "description": "<meaning>" }
  ],
  "notes": "<usage notes, thread safety, prerequisites>"
}

If a section has no items return []. Return ONLY the JSON object.

