// ── Parse JSON response — handles all known OpenAI/n8n response shapes ──────
const item = $input.first();

// Log the full response so you can inspect it in n8n's output panel
// (remove once working)
console.log('RAW ITEM KEYS:', JSON.stringify(Object.keys(item.json || {})));

const raw =
  // n8n OpenAI node (AI Agent / Chat Model)
  item.json?.choices?.[0]?.message?.content ||
  // OpenAI Responses API shape
  item.json?.output?.[0]?.content?.[0]?.text ||
  // Fallback: sometimes n8n wraps it under .text or .message
  item.json?.message?.content ||
  item.json?.text ||
  // Last resort: if the whole json IS the parsed object already
  (item.json?.overview ? JSON.stringify(item.json) : '{}');

let parsed;
try {
  const cleaned = raw
    .replace(/^```(?:json)?\r?\n?/, '')
    .replace(/\r?\n?```$/, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // If JSON parse fails, put the raw text in overview so you can see what GPT returned
  parsed = {
    overview: 'JSON parse failed. Raw response: ' + raw.slice(0, 500),
    functions: [],
    enumerators: [],
    data_types: [],
    constants: [],
    notes: ''
  };
}

// Try multiple places for fileName
const fileName =
  $('Process one file at a time')?.item?.json?.fileName ||
  $('Process one file at a time1')?.item?.json?.fileName ||
  item.json?.fileName ||
  'unknown.h';

return [{ json: { ...parsed, fileName } }];

// ═══════════════════════════════════════════════════════════════════════════
// GENERATE HTML FILE — outputs binary HTML file → save directly to Google Drive
// Replace "Generate PDF (zero dependencies)1" with this node.
// Then wire: this node → Save to Google Drive (upload file)
// ═══════════════════════════════════════════════════════════════════════════

const doc = $input.first().json;
const fileName = doc.fileName || 'unknown.h';
const baseName = fileName.replace(/\.[^/.]+$/, '');
const htmlName = 'DOC_' + baseName + '.html';
const today    = new Date().toISOString().slice(0, 10);

// ── Helpers ──────────────────────────────────────────────────────────────────
const esc = s => String(s || '')
  .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

function funcBlock(fn) {
  const params = fn.parameters || [];
  const paramRows = params.map(p => `
    <tr>
      <td><code>${esc(p.name)}</code></td>
      <td><code>${esc(p.type)}</code></td>
      <td>${esc(p.description)}</td>
    </tr>`).join('');

  return `
  <div class="card fn-block">
    <div class="fn-name">${esc(fn.name || '')}</div>
    <p class="fn-desc">${esc(fn.description || '')}</p>
    ${fn.signature ? `<div class="label">Signature</div><pre><code>${esc(fn.signature)}</code></pre>` : ''}
    ${params.length ? `
    <div class="label">Parameters</div>
    <div class="table-wrap"><table>
      <thead><tr><th>Parameter</th><th>Type</th><th>Description</th></tr></thead>
      <tbody>${paramRows}</tbody>
    </table></div>` : ''}
    ${fn.returns ? `<div class="label">Returns</div><p class="returns">${esc(fn.returns)}</p>` : ''}
    ${fn.example ? `<div class="label">Example</div><pre><code>${esc(fn.example)}</code></pre>` : ''}
  </div>`;
}

function dtBlock(dt) {
  const members = dt.members || [];
  const rows = members.map(m => `
    <tr>
      <td><code>${esc(m.name)}</code></td>
      <td><code>${esc(m.type)}</code></td>
      <td>${esc(m.description)}</td>
    </tr>`).join('');
  return `
  <div class="card">
    <div class="fn-name">${esc(dt.name || '')} <span class="kind-tag">${esc(dt.kind || '')}</span></div>
    <p>${esc(dt.description || '')}</p>
    ${members.length ? `
    <div class="label">Members</div>
    <div class="table-wrap"><table>
      <thead><tr><th>Member</th><th>Type</th><th>Description</th></tr></thead>
      <tbody>${rows}</tbody>
    </table></div>` : ''}
  </div>`;
}

function enumBlock(en) {
  const vals = en.values || [];
  const rows = vals.map(v => `
    <tr>
      <td><code>${esc(v.name)}</code></td>
      <td>${esc(v.value)}</td>
      <td>${esc(v.description)}</td>
    </tr>`).join('');
  return `
  <div class="card">
    <div class="fn-name">${esc(en.name || '')}</div>
    <p>${esc(en.description || '')}</p>
    ${vals.length ? `
    <div class="table-wrap"><table>
      <thead><tr><th>Enumerator</th><th>Value</th><th>Description</th></tr></thead>
      <tbody>${rows}</tbody>
    </table></div>` : ''}
  </div>`;
}

const fns    = doc.functions   || [];
const enums  = doc.enumerators || [];
const dts    = doc.data_types  || [];
const consts = doc.constants   || [];

const empty = label => `<p class="empty-state">No ${label} found in this header file.</p>`;

const fnHtml    = fns.length    ? fns.map(funcBlock).join('')    : empty('functions');
const enumHtml  = enums.length  ? enums.map(enumBlock).join('')  : empty('enumerators');
const dtHtml    = dts.length    ? dts.map(dtBlock).join('')      : empty('data types');
const constHtml = consts.length ? `
  <div class="card">
  <div class="table-wrap"><table>
    <thead><tr><th>Constant Name</th><th>Value</th><th>Description</th></tr></thead>
    <tbody>${consts.map(c=>`<tr><td><code>${esc(c.name)}</code></td><td>${esc(c.value)}</td><td>${esc(c.description)}</td></tr>`).join('')}</tbody>
  </table></div></div>` : empty('constants');

const tocItems = [
  ['1','Overview'],['2','Functions'],['3','Enumerators'],
  ['4','Data Types &amp; Structures'],['5','Constants'],['6','Notes']
];

const html = `<!DOCTYPE html>
