// Convert HTML string to base64 binary for Google Drive upload
const b64 = Buffer.from(html, 'utf8').toString('base64');

return [{
  json: {
    htmlName,
    fileName,
    timestamp: today
  },
  binary: {
    data: {
      data: b64,
      mimeType: 'text/html',
      fileName: htmlName,
      fileExtension: 'html'
    }
  }
}];
